parsed.css:
.renewal-risk { box-sizing: border-box; min-height: 900px; padding: 24px; background: #f6f7f9; color: #17202a; font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
.renewal-risk * { box-sizing: border-box; }
.risk-shell { display: grid; grid-template-columns: 280px minmax(0, 1fr) 360px; gap: 18px; max-width: 1320px; margin: 0 auto; }
.risk-header { grid-column: 1 / -1; display: flex; justify-content: space-between; align-items: flex-start; gap: 24px; padding-bottom: 6px; }
.eyebrow { margin: 0 0 6px; color: #5b6776; font-size: 12px; font-weight: 700; letter-spacing: .08em; text-transform: uppercase; }
h1, h2, h3, p { margin-top: 0; }
h1 { margin-bottom: 6px; font-size: 30px; line-height: 1.1; letter-spacing: 0; }
.header-note { margin: 0; color: #596575; font-size: 14px; }
.meeting-chip { display: inline-flex; align-items: center; gap: 8px; border: 1px solid #cfd6df; border-radius: 999px; padding: 8px 12px; background: #ffffff; color: #344255; font-size: 13px; font-weight: 700; white-space: nowrap; }
.panel { background: #ffffff; border: 1px solid #d9dee6; border-radius: 8px; box-shadow: 0 1px 2px rgba(23, 32, 42, .05); }
.queue { padding: 16px; }
.queue h2, .panel-title { margin-bottom: 12px; font-size: 15px; line-height: 1.25; }
.queue-list { display: grid; gap: 10px; }
.account-row { display: grid; gap: 4px; padding: 12px; border: 1px solid #e0e5ec; border-radius: 8px; background: #fbfcfd; }
.account-row.active { border-color: #285e61; background: #eef7f6; }
.row-top { display: flex; justify-content: space-between; gap: 12px; font-size: 13px; font-weight: 800; }
.row-state { color: #596575; font-size: 13px; }
.row-amount { color: #1f4f46; font-size: 13px; font-weight: 800; }
.main-stack { display: grid; gap: 18px; min-width: 0; }
.account-summary { padding: 18px; }
.summary-top { display: flex; justify-content: space-between; gap: 18px; align-items: flex-start; }
.customer-name { margin-bottom: 8px; font-size: 24px; line-height: 1.15; }
.meta-line { margin: 0; color: #546173; font-size: 14px; }
.status-badge { border-radius: 999px; padding: 8px 12px; background: #fff2d7; color: #7a4a00; font-size: 13px; font-weight: 800; white-space: nowrap; }
.metric-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; margin-top: 18px; }
.metric { border: 1px solid #e0e5ec; border-radius: 8px; padding: 12px; background: #fbfcfd; }
.metric-label { margin-bottom: 6px; color: #657184; font-size: 12px; font-weight: 700; text-transform: uppercase; }
.metric-value { color: #17202a; font-size: 18px; font-weight: 850; }
.evidence { padding: 18px; }
.evidence-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; }
.evidence-card { min-height: 138px; border: 1px solid #e0e5ec; border-radius: 8px; padding: 14px; background: #ffffff; }
.evidence-card.warning { border-top: 4px solid #b35c00; }
.evidence-card.critical { border-top: 4px solid #a93434; }
.evidence-card.gap { border-top: 4px solid #4f6f9f; }
.evidence-card h3 { margin-bottom: 8px; font-size: 14px; }
.evidence-card p { margin-bottom: 0; color: #3e4a59; font-size: 14px; line-height: 1.45; }
.policy-note { margin-top: 14px; border-left: 4px solid #285e61; padding: 12px 14px; background: #f0f7f5; color: #27413f; font-size: 14px; line-height: 1.45; }
.decision-panel { padding: 18px; align-self: start; }
.recommendation { margin-bottom: 16px; border: 1px solid #b9d6d1; border-radius: 8px; padding: 14px; background: #edf7f5; }
.recommendation h2 { margin-bottom: 8px; font-size: 16px; color: #163f3d; }
.recommendation p { margin-bottom: 0; color: #27413f; font-size: 14px; line-height: 1.45; }
.option-list { display: grid; gap: 10px; margin-bottom: 16px; }
.option { width: 100%; border: 1px solid #d8dee6; border-radius: 8px; padding: 12px; background: #ffffff; text-align: left; }
.option strong { display: block; margin-bottom: 4px; color: #17202a; font-size: 14px; }
.option span { display: block; color: #5b6776; font-size: 13px; line-height: 1.35; }
.option.primary { border-color: #285e61; background: #f2faf8; }
.option.blocked { background: #fafafa; color: #697586; }
.handoff { border-top: 1px solid #e2e6ec; padding-top: 16px; }
.handoff-row { display: grid; grid-template-columns: 112px 1fr; gap: 10px; padding: 8px 0; border-bottom: 1px solid #eef1f5; font-size: 14px; }
.handoff-row dt { color: #657184; font-weight: 700; }
.handoff-row dd { margin: 0; color: #17202a; }
.actions { display: flex; gap: 10px; margin-top: 16px; }
.button { border: 1px solid #285e61; border-radius: 8px; padding: 10px 12px; background: #285e61; color: #ffffff; font-size: 14px; font-weight: 800; }
.button.secondary { background: #ffffff; color: #285e61; }
@media (max-width: 980px) { .renewal-risk { min-height: auto; padding: 16px; } .risk-shell { grid-template-columns: 1fr; } .risk-header, .summary-top { flex-direction: column; } .evidence-grid, .metric-grid { grid-template-columns: 1fr; } }

